<template><div class="examination-page"><section class="page-hero compact lab-page-hero"><div><span class="eyebrow">{{mode==='待检查'?'PENDING TESTS':'REPORT ARCHIVE'}}</span><h1>{{mode==='待检查'?'待检查队列':'检验报告记录'}}</h1><p>{{mode==='待检查'?'核对申请信息，规范录入检查检验结果':'查询已完成报告，查看结果与附件'}}</p></div><div class="hero-metric"><span>{{mode==='待检查'?'等待处理':'累计报告'}}</span><strong>{{total}}</strong><small>项</small></div></section><section class="content-card"><div class="toolbar"><div class="search"><el-input v-model="keyword" :prefix-icon="Search" placeholder="搜索患者、医生或检查项目" clearable/><el-select v-model="typeFilter" placeholder="全部类型" clearable><el-option label="检验" value="检验"/><el-option label="检查" value="检查"/></el-select><el-date-picker v-model="date" type="date" value-format="YYYY-MM-DD" placeholder="申请日期" clearable/></div><el-button :icon="Refresh" @click="loadData">刷新</el-button></div><el-table :data="filtered" v-loading="loading" class="pharmacy-table"><el-table-column label="申请单" min-width="170"><template #default="{row}"><div class="rx lab-order"><span>EX</span><div><strong>EX{{String(row.id).padStart(6,'0')}}</strong><small>{{formatDate(row.createTime)}}</small></div></div></template></el-table-column><el-table-column label="患者" min-width="145"><template #default="{row}"><div class="person"><span>{{row.patientName?.slice(0,1)}}</span><div><strong>{{row.patientName}}</strong><small>患者ID {{row.patientId}}</small></div></div></template></el-table-column><el-table-column prop="itemName" label="检查项目" min-width="170"/><el-table-column label="类型" min-width="90"><template #default="{row}"><el-tag :type="row.type==='检验'?'success':'primary'" effect="light" round>{{row.type}}</el-tag></template></el-table-column><el-table-column label="开单医生" min-width="120"><template #default="{row}">{{row.doctorName}} 医生</template></el-table-column><el-table-column label="状态" min-width="100"><template #default="{row}"><el-tag :type="row.status==='待检查'?'warning':'success'" round effect="light">{{row.status}}</el-tag></template></el-table-column><el-table-column v-if="mode==='已完成'" label="完成时间" min-width="160"><template #default="{row}">{{formatDate(row.completeTime)}}</template></el-table-column><el-table-column label="操作" width="170" fixed="right"><template #default="{row}"><el-button link type="primary" @click="openDetail(row)">查看详情</el-button><el-button v-if="row.status==='待检查'" type="primary" size="small" @click="openReport(row)">录入结果</el-button></template></el-table-column></el-table><div class="pagination"><span>共 {{total}} 条记录</span><el-pagination v-model:current-page="page" :page-size="size" :total="total" layout="prev,pager,next" @current-change="loadData"/></div></section><el-drawer v-model="drawer" size="600px" :with-header="false"><div v-if="current" class="report-detail"><div class="drawer-head"><span class="rx-logo"><el-icon><DataAnalysis/></el-icon></span><div><small>LABORATORY REPORT</small><h2>{{current.status==='待检查'?'录入检验结果':'检验报告详情'}}</h2><p>EX{{String(current.id).padStart(6,'0')}}</p></div><button @click="drawer=false"><el-icon><Close/></el-icon></button></div><div class="patient-banner"><div><span>患者姓名</span><strong>{{current.patientName}}</strong></div><div><span>检查项目</span><strong>{{current.itemName}}</strong></div><div><span>开单医生</span><strong>{{current.doctorName}} 医生</strong></div></div><div class="report-meta"><span><b>申请时间</b>{{formatDate(current.createTime)}}</span><span><b>检查类型</b>{{current.type}}</span><span><b>当前状态</b>{{current.status}}</span></div><template v-if="current.status==='待检查'"><div class="template-row"><span>快捷模板</span><el-button v-for="t in templates" :key="t.label" size="small" plain @click="form.result=t.text">{{t.label}}</el-button></div><label class="field-label">检查结果 <em>*</em></label><el-input v-model="form.result" type="textarea" :rows="10" maxlength="3000" show-word-limit placeholder="请准确、完整地录入检查结果；异常指标请重点标注……"/><label class="field-label">报告附件</label><div class="upload-box"><input ref="fileInput" type="file" accept="image/*" multiple @change="handleFiles"/><button @click="fileInput?.click()"><el-icon><UploadFilled/></el-icon><strong>上传报告图片</strong><span>支持 JPG、PNG，单张不超过 10MB</span></button><div v-if="images.length" class="image-list"><div v-for="(img,i) in images" :key="img"><img :src="img"/><button @click="images.splice(i,1)"><el-icon><Close/></el-icon></button></div></div></div><div class="submit-tip"><el-icon><Warning/></el-icon><span>提交后报告将立即同步，且不可再次修改，请确认结果无误。</span></div><el-button type="primary" size="large" class="dispense-btn" :loading="saving" :disabled="!form.result.trim()" @click="submitResult">确认结果并发布报告</el-button></template><template v-else><h3 class="result-title">检查结果</h3><div class="result-content">{{current.result}}</div><div v-if="imageUrls(current.resultImages).length" class="report-images"><img v-for="img in imageUrls(current.resultImages)" :key="img" :src="img"/></div><div class="done-banner"><el-icon><CircleCheckFilled/></el-icon><div><strong>报告已完成并发布</strong><span>{{formatDate(current.completeTime)}}</span></div></div></template></div></el-drawer></div></template>
<script setup lang="ts">import{computed,ref,watch}from'vue';import{ElMessage,ElMessageBox}from'element-plus';import{Search,Refresh,DataAnalysis,Close,UploadFilled,Warning,CircleCheckFilled}from'@element-plus/icons-vue';import{getExamination,getExaminations,updateResult,uploadFile}from'@/api/lab';import type{Examination}from'@/types';const props=defineProps<{mode:string}>(),loading=ref(false),saving=ref(false),page=ref(1),size=ref(10),total=ref(0),list=ref<Examination[]>([]),keyword=ref(''),typeFilter=ref(''),date=ref(''),drawer=ref(false),current=ref<Examination>(),fileInput=ref<HTMLInputElement>(),images=ref<string[]>([]),form=ref({result:''});const templates=[{label:'结果正常',text:'检查结果未见明显异常。'},{label:'血常规',text:'白细胞计数：\n红细胞计数：\n血红蛋白：\n血小板计数：\n结论：'},{label:'生化检验',text:'检测指标：\n检测结果：\n参考范围：\n结论：'}];const formatDate=(s?:string)=>s?new Date(s).toLocaleString('zh-CN',{year:'numeric',month:'2-digit',day:'2-digit',hour:'2-digit',minute:'2-digit'}):'--';const imageUrls=(s?:string)=>s?s.split(',').filter(Boolean):[];const filtered=computed(()=>list.value.filter(x=>(!keyword.value||x.patientName?.includes(keyword.value)||x.doctorName?.includes(keyword.value)||x.itemName?.includes(keyword.value)||String(x.id).includes(keyword.value))&&(!typeFilter.value||x.type===typeFilter.value)&&(!date.value||x.createTime?.startsWith(date.value))));const loadData=async()=>{loading.value=true;try{const r=await getExaminations(props.mode,page.value,size.value);list.value=r.data.data.content;total.value=r.data.data.totalElements}finally{loading.value=false}};const openDetail=async(row:Examination)=>{current.value=(await getExamination(row.id)).data.data;form.value.result=current.value.result||'';images.value=imageUrls(current.value.resultImages);drawer.value=true};const openReport=openDetail;const handleFiles=async(e:Event)=>{const files=Array.from((e.target as HTMLInputElement).files||[]);for(const file of files){if(file.size>10*1024*1024){ElMessage.warning(`${file.name} 超过10MB`);continue}const r=await uploadFile(file);images.value.push(r.data.data)}if(fileInput.value)fileInput.value.value=''};const submitResult=async()=>{await ElMessageBox.confirm('报告发布后不可修改，确认检查结果已经复核无误？','发布检验报告',{type:'warning',confirmButtonText:'确认发布'});saving.value=true;try{await updateResult({id:current.value!.id,result:form.value.result,resultImages:images.value.join(',')||undefined});ElMessage.success('检验报告发布成功');drawer.value=false;loadData()}finally{saving.value=false}};watch(()=>props.mode,()=>{page.value=1;loadData()},{immediate:true})</script>
